// Check if any page block has confidence < 0.70
const pages = $input.first().json.pages || [];
const lowConfPages = [];

for (const page of pages) {
  const blocks = page.blocks || [];
  const hasLowConf = blocks.some(b => (b.confidence ?? 1) < 0.70);
  if (hasLowConf) {
    lowConfPages.push({
      page_num: page.page_num,
      blocks: blocks,
      document_id: $('Webhook Trigger').first().json.document_id
    });
  }
}

// Pass through all pages + flag low confidence ones
return [{
  json: {
    all_pages: pages,
    low_conf_pages: lowConfPages,
    has_low_conf: lowConfPages.length > 0,
    document_id: $('Webhook Trigger').first().json.document_id,
    tender_id: $('Webhook Trigger').first().json.tender_id,
    bidder_id: $('Webhook Trigger').first().json.bidder_id
  }
}];

// Build vision prompt payload for each low-confidence page
// In production: render PDF page to base64 image via a helper endpoint
// FastAPI endpoint: GET /documents/{id}/page/{num}/image?format=base64
const lowPages = $json.low_conf_pages || [];
const docId = $json.document_id;

return lowPages.map(page => ({
  json: {
    document_id: docId,
    page_num: page.page_num,
    image_url: `http://backend:8000/api/v1/documents/${docId}/page/${page.page_num}/image`
  }
}));

