// Merge gemma3 vision output back into page_blocks
const allPages = $('Check Confidence').first().json.all_pages;
const visionItems = $input.all();

// Build a map of page_num -> vision text
const visionMap = {};
for (const item of visionItems) {
  const pageNum = item.json.page_num;
  const visionText = item.json.choices?.[0]?.message?.content || '';
  visionMap[pageNum] = visionText;
}

// Replace low-confidence blocks with vision extraction
const mergedPages = allPages.map(page => {
  if (visionMap[page.page_num]) {
    return {
      ...page,
      blocks: [{
        block_type: 'text',
        text: visionMap[page.page_num],
        confidence: 0.88,
        source: 'gemma3_vision'
      }]
    };
  }
  return page;
});

return [{
  json: {
    all_pages: mergedPages,
    document_id: $('Webhook Trigger').first().json.document_id,
    tender_id: $('Webhook Trigger').first().json.tender_id,
    bidder_id: $('Webhook Trigger').first().json.bidder_id
  }
}];

// Pass pages straight through when all confidence >= 0.70
const data = $input.first().json;
return [{ json: data }];

// Assemble the full Structured Document Object
// Receives from either merge-vision or pass-through path
const data = $input.first().json;
const webhookData = $('Webhook Trigger').first().json;

const allBlocks = [];
for (const page of (data.all_pages || [])) {
  for (const block of (page.blocks || [])) {
    allBlocks.push({
      block_id: `${data.document_id}-p${page.page_num}-${allBlocks.length}`,
      page_num: page.page_num,
      block_type: block.block_type || 'text',
      text: block.text || '',
      confidence: block.confidence ?? 1.0,
      source: block.source || 'docling',
      bbox: block.bbox || null
    });
  }
}

const sdo = {
  document_id: data.document_id || webhookData.document_id,
  tender_id: data.tender_id || webhookData.tender_id,
  bidder_id: data.bidder_id || webhookData.bidder_id,
  filename: webhookData.filename,
  file_type: webhookData.file_type,
  total_pages: (data.all_pages || []).length,
  total_blocks: allBlocks.length,
  blocks: allBlocks,
  ingestion_timestamp: new Date().toISOString(),
  input_hash: webhookData.input_hash || null
};

return [{ json: sdo }];

// Attach embedding vector back onto the block
const block = $input.first().json;
const embeddingResponse = block; // HTTP response is inline
const vector = block.data?.[0]?.embedding || [];

// Grab original block data passed through the split
// We need to carry forward the block metadata
return [{
  json: {
    block_id: block.block_id,
    document_id: block.document_id,
    tender_id: block.tender_id,
    bidder_id: block.bidder_id,
    page_num: block.page_num,
    block_type: block.block_type,
    text: block.text,
    confidence: block.confidence,
    vector: vector
  }
}];

// Aggregate all items back and build the final SDO
// At this point all blocks have been embedded and upserted
// We now POST the full SDO to FastAPI
const allItems = $input.all();

// Reconstruct SDO from the split items
const first = allItems[0]?.json || {};
const sdo = {
  document_id: first.document_id,
  tender_id: first.tender_id,
  bidder_id: first.bidder_id,
  total_blocks: allItems.length,
  blocks_upserted_to_qdrant: allItems.length,
  ingestion_complete: true,
  completed_at: new Date().toISOString()
};

return [{ json: sdo }];
